// ═══════════════════════════════════════════════════════════════
// STRUCTURATION DES DONNÉES PAR DESTINATAIRE — AUTORISATIONS DE SORTIE
// Niveaux : PDG / SUPERIEUR / SALARIE / FARHAT / DGA / JAOUD
// DGA et JAOUD = même seuil : jours_restants <= délai/2
// ═══════════════════════════════════════════════════════════════

const items = $input.all();

console.log('\n═══════════════════════════════════════════════════');
console.log('📊 STRUCTURATION DES NOTIFICATIONS - AUTORISATIONS DE SORTIE (avec JAOUD)');
console.log('═══════════════════════════════════════════════════');
console.log(`Autorisations reçues: ${items.length}`);

const notifications = {};

items.forEach(item => {
  const data = item.json;

  let destinatairePrincipal;
  let codeDestinataire;
  let typeDestinataire;

  if (data.niveau_escalade === 'PDG') {
    destinatairePrincipal = {
      code: data.code_pdg, nom: data.nom_pdg, prenom: data.prenom_pdg,
      email: data.email_pdg, telephone: data.telephone_pdg,
      chat_id: data.chat_id_pdg, langue: data.langue_pdg, bot: data.bot_pdg
    };
    codeDestinataire = data.code_pdg;
    typeDestinataire = 'PDG';

  } else if (data.niveau_escalade === 'SUPERIEUR') {
    destinatairePrincipal = {
      code: data.code_superieur, nom: data.nom_superieur, prenom: data.prenom_superieur,
      email: data.email_superieur, telephone: data.telephone_superieur,
      chat_id: data.chat_id_superieur, langue: data.langue_superieur, bot: data.bot_superieur
    };
    codeDestinataire = data.code_superieur;
    typeDestinataire = 'SUPERIEUR';

  } else if (data.niveau_escalade === 'SALARIE') {
    destinatairePrincipal = {
      code: data.code_salarie, nom: data.nom_salarie, prenom: data.prenom_salarie,
      email: data.email_salarie, telephone: data.telephone_salarie,
      chat_id: data.chat_id_salarie, langue: data.langue_salarie, bot: data.bot_salarie
    };
    codeDestinataire = data.code_salarie;
    typeDestinataire = 'SALARIE';

  } else if (data.niveau_escalade === 'FARHAT') {
    destinatairePrincipal = {
      code: data.code_farhat, nom: data.nom_farhat, prenom: data.prenom_farhat,
      email: data.email_farhat || null, telephone: data.telephone_farhat || null,
      chat_id: data.chat_id_farhat || null, langue: data.langue_farhat || 'FRA', bot: data.bot_farhat || null
    };
    codeDestinataire = data.code_farhat;
    typeDestinataire = 'FARHAT';

  } else if (data.niveau_escalade === 'DGA') {
    // Email uniquement, pas de Telegram
    destinatairePrincipal = {
      code: data.code_dga, nom: data.nom_dga, prenom: data.prenom_dga,
      email: data.email_dga || null, telephone: data.telephone_dga || null,
      chat_id: null, langue: data.langue_dga || 'FRA', bot: null
    };
    codeDestinataire = data.code_dga;
    typeDestinataire = 'DGA';

  } else if (data.niveau_escalade === 'JAOUD') {
    // ─── JAOUD : même seuil que DGA, email uniquement ───
    destinatairePrincipal = {
      code: data.code_jaoud, nom: data.nom_jaoud, prenom: data.prenom_jaoud,
      email: data.email_jaoud || null, telephone: data.telephone_jaoud || null,
      chat_id: null,  // pas de Telegram pour Jaoud
      langue: data.langue_jaoud || 'FRA', bot: null
    };
    codeDestinataire = data.code_jaoud;
    typeDestinataire = 'JAOUD';

  } else {
    console.log(`⏭️  Autorisation ${data.numero_autorisation} ignorée (niveau: ${data.niveau_escalade})`);
    return;
  }

  const cleDestinataire = `${typeDestinataire}_${codeDestinataire}`;

  if (!notifications[cleDestinataire]) {
    notifications[cleDestinataire] = {
      destinataire_principal: destinatairePrincipal,
      type_destinataire: typeDestinataire,
      niveau_escalade: data.niveau_escalade,

      salarie: {
        code: data.code_salarie, nom: data.nom_salarie, prenom: data.prenom_salarie,
        email: data.email_salarie, telephone: data.telephone_salarie,
        chat_id: data.chat_id_salarie, langue: data.langue_salarie, bot: data.bot_salarie
      },
      superieur: {
        code: data.code_superieur, nom: data.nom_superieur, prenom: data.prenom_superieur,
        email: data.email_superieur, telephone: data.telephone_superieur,
        chat_id: data.chat_id_superieur, langue: data.langue_superieur, bot: data.bot_superieur
      },
      pdg: {
        code: data.code_pdg, nom: data.nom_pdg, prenom: data.prenom_pdg,
        email: data.email_pdg, telephone: data.telephone_pdg,
        chat_id: data.chat_id_pdg, langue: data.langue_pdg, bot: data.bot_pdg
      },
      dga: {
        code: data.code_dga, nom: data.nom_dga, prenom: data.prenom_dga,
        email: data.email_dga, telephone: data.telephone_dga,
        chat_id: null, langue: data.langue_dga || 'FRA', bot: null
      },
      farhat: {
        code: data.code_farhat, nom: data.nom_farhat, prenom: data.prenom_farhat,
        email: data.email_farhat, telephone: data.telephone_farhat,
        chat_id: data.chat_id_farhat, langue: data.langue_farhat, bot: data.bot_farhat
      },
      jaoud: {
        code: data.code_jaoud, nom: data.nom_jaoud, prenom: data.prenom_jaoud,
        email: data.email_jaoud, telephone: data.telephone_jaoud,
        chat_id: null, langue: data.langue_jaoud || 'FRA', bot: null
      },

      autorisations: []
    };
  }

  notifications[cleDestinataire].autorisations.push({
    numero_autorisation:  data.numero_autorisation,
    date_creation:        data.date_creation,
    date_controle:        data.date_controle,
    utilisateur_createur: data.utilisateur_createur,
    date_sortie:          data.date_sortie,
    heure_sortie:         data.heure_sortie,
    heure_retour:         data.heure_retour,
    descriptif:           data.descriptif,
    nb_heures_absence:    data.nb_heures_absence,
    motif:                data.motif,
    delai_total_jours:    data.delai_total_jours,
    date_limite:          data.date_limite,
    jours_depuis_creation:data.jours_depuis_creation,
    jours_restants:       data.jours_restants,
    salarie_concerne: {
      code: data.code_salarie, nom: data.nom_salarie, prenom: data.prenom_salarie,
      email: data.email_salarie, telephone: data.telephone_salarie
    }
  });
});

const resultats = Object.values(notifications).map(notif => {
  const totalAutorisations = notif.autorisations.length;
  const joursMin   = Math.min(...notif.autorisations.map(a => a.jours_restants));
  const joursMax   = Math.max(...notif.autorisations.map(a => a.jours_restants));
  const delaiTotal = parseInt(notif.autorisations[0]?.delai_total_jours) || 10;

  let emailCC   = [];
  let chatIDsCC = [];

  if (notif.type_destinataire === 'PDG') {
    if (notif.superieur.email)   emailCC.push(notif.superieur.email);
    if (notif.salarie.email)     emailCC.push(notif.salarie.email);
    if (notif.superieur.chat_id) chatIDsCC.push({ chat_id: notif.superieur.chat_id, bot: notif.superieur.bot, langue: notif.superieur.langue, nom: `${notif.superieur.prenom} ${notif.superieur.nom}` });
    if (notif.salarie.chat_id)   chatIDsCC.push({ chat_id: notif.salarie.chat_id,   bot: notif.salarie.bot,   langue: notif.salarie.langue,   nom: `${notif.salarie.prenom} ${notif.salarie.nom}`   });
  } else if (notif.type_destinataire === 'SUPERIEUR') {
    if (notif.salarie.email)     emailCC.push(notif.salarie.email);
    if (notif.salarie.chat_id)   chatIDsCC.push({ chat_id: notif.salarie.chat_id, bot: notif.salarie.bot, langue: notif.salarie.langue, nom: `${notif.salarie.prenom} ${notif.salarie.nom}` });
  }
  // DGA, JAOUD, FARHAT, SALARIE → pas de CC

  return {
    destinataire_principal: notif.destinataire_principal,
    type_destinataire:      notif.type_destinataire,
    niveau_escalade:        notif.niveau_escalade,
    email_cc:    emailCC.length   > 0 ? emailCC.join(',') : null,
    telegram_cc: chatIDsCC.length > 0 ? chatIDsCC         : null,
    salarie:   notif.salarie,
    superieur: notif.superieur,
    pdg:       notif.pdg,
    dga:       notif.dga,
    farhat:    notif.farhat,
    jaoud:     notif.jaoud,
    autorisations: notif.autorisations,
    statistiques: {
      total_autorisations: totalAutorisations,
      jours_min:   joursMin,
      jours_max:   joursMax,
      priorite:    notif.niveau_escalade,
      delai_total: delaiTotal,
      seuil_dga:   Math.floor(delaiTotal / 2),
      seuil_jaoud: Math.floor(delaiTotal / 2)   // identique au DGA
    },
    meta: {
      date_traitement:       new Date().toISOString(),
      langue_message:        notif.destinataire_principal.langue || 'FRA',
      peut_envoyer_email:    !!notif.destinataire_principal.email,
      peut_envoyer_telegram: !!notif.destinataire_principal.chat_id
    }
  };
});

console.log(`\n✅ Notifications structurées: ${resultats.length}`);
console.log('Par type:');
console.log(`  - PDG:       ${resultats.filter(r => r.type_destinataire === 'PDG').length}`);
