function formaterDate(dateStr, langue) {
  if (!dateStr) return 'N/A';
  try {
    const date = new Date(dateStr);
    const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
    return date.toLocaleDateString(locale, { year: 'numeric', month: '2-digit', day: '2-digit' });
  } catch(e) { return dateStr; }
}

function formaterDateHeure(dateStr, langue) {
  if (!dateStr) return 'N/A';
  try {
    const date = new Date(dateStr);
    const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
    return date.toLocaleString(locale, { year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
  } catch(e) { return dateStr; }
}

function formaterHeure(heureVal) {
  if (!heureVal && heureVal !== 0) return 'N/A';
  if (typeof heureVal === 'number') {
    const h = Math.floor(heureVal / 60).toString().padStart(2, '0');
    const m = (heureVal % 60).toString().padStart(2, '0');
    return `${h}:${m}`;
  }
  return String(heureVal);
}

function getEmoji(jours) {
  if (jours <= 2) return '🔴';
  if (jours === 3) return '🟠';
  if (jours === 4) return '🟡';
  if (jours <= 8) return '🔵';
  return '🟢';
}

// Les deux niveaux qui partagent le seuil mi-délai
const MI_DELAI_LEVELS = ['DGA', 'JAOUD'];

function genererMessagePrincipal(data) {
  const langue = data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const destinataire = data.destinataire_principal;
  const stats = data.statistiques;
  const autorisations = data.autorisations;

  const isMiDelai = MI_DELAI_LEVELS.includes(data.type_destinataire);

  let emailSubject = (T.sujet_email[data.type_destinataire] || T.sujet_email.SALARIE)
                   + ` - ${stats.total_autorisations} autorisation(s)`;

  let emailBody = `${T.salutation} ${destinataire.prenom} ${destinataire.nom},\n\n`;
  emailBody += `${T.introduction[data.type_destinataire]}\n\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📊 ${T.section_stats}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau d'escalade: ${data.niveau_escalade}\n`;
  emailBody += `${T.total}: ${stats.total_autorisations}\n`;
  emailBody += `${T.delai_min}: ${stats.jours_min} ${T.jours}\n`;
  emailBody += `${T.delai_total}: ${stats.delai_total} ${T.jours}\n`;

  // Seuil affiché pour DGA et JAOUD
  if (isMiDelai) {
    emailBody += `${T.seuil_dga}: ${stats.seuil_dga} ${T.jours}\n`;
  }

  emailBody += `\n═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📋 ${T.section_autorisations}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  autorisations.forEach((aut, index) => {
    emailBody += `${index + 1}. ${getEmoji(aut.jours_restants)} ${aut.numero_autorisation}\n`;
    emailBody += `   📅 ${T.date_creation}: ${formaterDateHeure(aut.date_creation, langue)}\n`;
    emailBody += `   🧑 ${T.salarie_concerne}: ${aut.salarie_concerne.prenom} ${aut.salarie_concerne.nom} (${aut.salarie_concerne.code})\n`;
    emailBody += `   📆 ${T.date_sortie}: ${formaterDate(aut.date_sortie, langue)}\n`;
    emailBody += `   🕐 ${T.heure_sortie}: ${formaterHeure(aut.heure_sortie)} → ${T.heure_retour}: ${formaterHeure(aut.heure_retour)}\n`;
    if (aut.motif) emailBody += `   📝 ${T.motif}: ${aut.motif}\n`;
    if (aut.nb_heures_absence) emailBody += `   ⏱️  ${T.nb_heures}: ${aut.nb_heures_absence}h\n`;
    emailBody += `   ⏰ ${T.delai}: ${aut.jours_restants} ${T.jours} ${T.restant} (${T.limite}: ${formaterDate(aut.date_limite, langue)})\n`;
    if (aut.jours_restants <= 2) emailBody += `   🚨 ${T.urgent}\n`;
    emailBody += `\n`;
  });

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  if (stats.jours_min <= 2) {
    emailBody += `🚨 ${T.action_requise}: ${T.urgent}\n`;
  } else if (isMiDelai) {
    emailBody += `📌 ${T.instruction_mi_delai}\n`;
  } else {
    emailBody += `📌 ${T.instruction}\n`;
  }
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  emailBody += `📞 ${T.contact}:\n`;
  if (data.superieur && data.superieur.email) {
    emailBody += `   ${data.superieur.prenom} ${data.superieur.nom}\n`;
    emailBody += `   Email: ${data.superieur.email}\n`;
    emailBody += `   Tel: ${data.superieur.telephone || 'N/A'}\n`;
  }
  emailBody += `\n${T.cordialement},\n\n${T.signature}\n\n`;
  emailBody += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  emailBody += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString(), langue)}\n`;
  if (data.type_destinataire === 'PDG')   emailBody += `🔴 Notification URGENTE envoyée au PDG\n`;
  if (data.type_destinataire === 'DGA')   emailBody += `🟠 Notification DGA (seuil mi-délai: ${stats.seuil_dga}j)\n`;
  if (data.type_destinataire === 'JAOUD') emailBody += `🟠 Notification JAOUD Baalah (seuil mi-délai: ${stats.seuil_jaoud}j)\n`;
  emailBody += `${T.ne_pas_repondre}\n`;

  // ── Telegram (DGA et JAOUD ont chat_id null → ce bloc ne sera jamais atteint pour eux) ──
  let telegramMessage = `${getEmoji(stats.jours_min)} *${T.sujet_email[data.type_destinataire]}*\n`;
  telegramMessage += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  telegramMessage += `👤 *${destinataire.prenom} ${destinataire.nom}*\n\n`;
  telegramMessage += `📊 *${T.section_stats}*\n`;
  telegramMessage += `${T.total}: *${stats.total_autorisations}*\n`;
  telegramMessage += `${T.delai_min}: *${stats.jours_min} ${T.jours}*\n\n`;
  telegramMessage += `📋 *Autorisations:*\n\n`;
  autorisations.slice(0, 5).forEach((aut, index) => {
    telegramMessage += `${index + 1}. ${getEmoji(aut.jours_restants)} *${aut.numero_autorisation}*\n`;
    telegramMessage += `   🧑 ${aut.salarie_concerne.prenom} ${aut.salarie_concerne.nom}\n`;
    telegramMessage += `   📆 ${formaterDate(aut.date_sortie, langue)} ${formaterHeure(aut.heure_sortie)}→${formaterHeure(aut.heure_retour)}\n`;
    if (aut.motif) telegramMessage += `   📝 ${aut.motif}\n`;
    telegramMessage += `   ⏰ ${aut.jours_restants} ${T.jours} ${T.restant}\n\n`;
  });
  if (autorisations.length > 5) telegramMessage += `... et ${autorisations.length - 5} autre(s) autorisation(s)\n\n`;
  if (stats.jours_min <= 2) telegramMessage += `🚨 *${T.urgent}*\n\n`;

  return {
    email:    { subject: emailSubject, body: emailBody },
    telegram: { text: telegramMessage, parse_mode: 'Markdown' }
  };
}

function genererMessageCC(data, destinataireCC, typeDestinatairePrincipal) {
  const langue = destinataireCC.langue || data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;
  const stats = data.statistiques;
  const autorisations = data.autorisations;
  const destinatairePrincipal = data.destinataire_principal;

  const labels = {
    SUPERIEUR: T.cc_message.votre_superieur,
    PDG:       T.cc_message.le_pdg,
    DGA:       T.cc_message.le_dga,
    JAOUD:     T.cc_message.le_jaoud,
    FARHAT:    T.cc_message.le_farhat
  };
  const label = labels[typeDestinatairePrincipal] || typeDestinatairePrincipal;
  const msg_envoye_a = `${label} ${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}`;

  let emailSubject = `${T.copie_info} - ${T.sujet_email[typeDestinatairePrincipal]} - ${stats.total_autorisations} autorisation(s)`;
  let emailBody = `${T.salutation} ${destinataireCC.prenom} ${destinataireCC.nom},\n\n`;
  emailBody += `${T.cc_message.base} ${msg_envoye_a}.\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau: ${data.niveau_escalade} | ${T.total}: ${stats.total_autorisations} | ${T.delai_min}: ${stats.jours_min} ${T.jours}\n\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📋 ${T.section_autorisations}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  autorisations.forEach((aut, index) => {
    emailBody += `${index + 1}. ${getEmoji(aut.jours_restants)} ${aut.numero_autorisation}\n`;
    emailBody += `   🧑 ${aut.salarie_concerne.prenom} ${aut.salarie_concerne.nom} | 📆 ${formaterDate(aut.date_sortie, langue)} | ⏰ ${aut.jours_restants} ${T.jours} ${T.restant}\n`;
    if (aut.motif) emailBody += `   📝 ${aut.motif}\n`;
    emailBody += `\n`;
  });
  emailBody += `${T.cc_message.action}\n\n`;
  emailBody += `${T.cordialement},\n\n${T.signature}\n`;
  emailBody += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  emailBody += `🤖 ${T.message_auto} | ${T.copie_info} | ${T.ne_pas_repondre}\n`;

  let telegramMessage = `${T.copie_info}\n━━━━━━━━━━━━━━━━━━━━━\n\n`;
  telegramMessage += `${T.salutation} *${destinataireCC.prenom} ${destinataireCC.nom}*,\n\n`;
  telegramMessage += `${T.cc_message.base} ${msg_envoye_a}.\n\n`;
  telegramMessage += `📊 ${T.total}: *${stats.total_autorisations}* | ${T.delai_min}: *${stats.jours_min} ${T.jours}*\n\n`;
  autorisations.slice(0, 3).forEach((aut, index) => {
    telegramMessage += `${index + 1}. ${getEmoji(aut.jours_restants)} *${aut.numero_autorisation}*\n`;
    telegramMessage += `   🧑 ${aut.salarie_concerne.prenom} ${aut.salarie_concerne.nom}\n`;
    telegramMessage += `   📆 ${formaterDate(aut.date_sortie, langue)} | ⏰ ${aut.jours_restants} ${T.jours} ${T.restant}\n\n`;
  });
  if (autorisations.length > 3) telegramMessage += `... et ${autorisations.length - 3} autre(s)\n\n`;
  telegramMessage += `${T.cc_message.action}\n`;

  return {
    email:    { subject: emailSubject, body: emailBody },
    telegram: { text: telegramMessage, parse_mode: 'Markdown' }
  };
}

const results = [];

inputData.forEach(item => {
  const data = item.json;
  const messagesPrincipal = genererMessagePrincipal(data);

  results.push({
    json: {
      ...data,
      messages:           messagesPrincipal,
      type_envoi:         'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      meta: { ...data.meta, langue_utilisee: data.meta.langue_message || 'FRA', date_generation: new Date().toISOString() }
    }
  });

  // CC : SUPERIEUR → copie au salarié
  if (data.type_destinataire === 'SUPERIEUR' && data.salarie?.chat_id) {
    const messagesCC = genererMessageCC(data, data.salarie, 'SUPERIEUR');
    results.push({ json: { ...data, messages: messagesCC, type_envoi: 'CC', destinataire_final: data.salarie, cc_pour_profil: 'SALARIE', meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() } } });
  }

  // CC : PDG → copie au supérieur ET au salarié
  if (data.type_destinataire === 'PDG') {
    if (data.superieur?.chat_id) {
      const msgCCSup = genererMessageCC(data, data.superieur, 'PDG');
      results.push({ json: { ...data, messages: msgCCSup, type_envoi: 'CC', destinataire_final: data.superieur, cc_pour_profil: 'SUPERIEUR', meta: { ...data.meta, langue_utilisee: data.superieur.langue || 'FRA', date_generation: new Date().toISOString() } } });
    }
    if (data.salarie?.chat_id) {
      const msgCCSal = genererMessageCC(data, data.salarie, 'PDG');
      results.push({ json: { ...data, messages: msgCCSal, type_envoi: 'CC', destinataire_final: data.salarie, cc_pour_profil: 'SALARIE', meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() } } });
    }
  }

  // DGA  → email uniquement, pas de CC, pas de Telegram
  // JAOUD → email uniquement, pas de CC, pas de Telegram
  // FARHAT → CC salarié si chat_id
  if (data.type_destinataire === 'FARHAT' && data.salarie?.chat_id) {
    const messagesCC = genererMessageCC(data, data.salarie, 'FARHAT');
    results.push({ json: { ...data, messages: messagesCC, type_envoi: 'CC', destinataire_final: data.salarie, cc_pour_profil: 'SALARIE', meta: { ...data.meta, langue_utilisee: data.salarie.langue || 'FRA', date_generation: new Date().toISOString() } } });
  }
});

